import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSSecureCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            // Properly handle user input by encoding it before printing
            HTMLEntityCodec codec = new HTMLEntityCodec();
            String encodedInput = codec.encodeForHTML(userInput);
            System.out.println("Welcome, " + encodedInput + "!");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

